module mux_4to1(data_in_0, in1, in2, in3, sel, out);

    input  data_in_0;
    input  in1;
    input  in2;
    input  in3;
    input  [1:0] sel;
    output reg out;

    always @(sel or data_in_0 or in1 or in2 or in3) begin
        case (sel)
            2'b00: out = data_in_0;
            2'b01: out = in1;
            2'b10: out = in2;
            2'b11: out = in3;
            default: out = 1'b0;
        endcase
    end

endmodule
